import JSZip from "jszip";

const SavePromisesToZip = async (promises) => {
  let promise = new Promise(async (resolve) => {
    const data = await Promise.all(promises);
    let zip = new JSZip();

    let strings = data.reduce(({ str, metadataStr }, blob, idx) => {
      if (blob) {
        zip.file(`${idx}.${blob.type}`, blob.data);

        console.log(blob);
        str += `${idx}.`;
        metadataStr += `${idx} | ${blob.metadata.date}\n`
        metadataStr += `  Description:\n`
        metadataStr += `    ${blob.metadata.description || "N/A"}`
        metadataStr += "\n"
        metadataStr += `  Tagged Characters:\n`
        blob.metadata.tagged_characters.forEach(character => {
          metadataStr += `    ${character.name} | ${character.profile}\n`
        })
        metadataStr += "\n"

        blob.artists.forEach((artist, index) => {
          str += ` ${artist.name} | [ ${artist.profile} ]`;
          if(index !== blob.artists.length - 1) str += ',';
        })
        str += "\n"
        
      }

      return {str, metadataStr};
    }, { str: "", metadataStr: "" });


    zip.file("credits.txt", strings.str);
    zip.file("metadata.txt", strings.metadataStr)
    resolve(zip);
  });

  return promise;
};

export default SavePromisesToZip;
